import { DataSource } from 'typeorm';
import { Role } from '../entities/role.entity';

export async function seedInitialRoles(dataSource: DataSource) {
  const roleRepository = dataSource.getRepository(Role);
  const roles = [
    { name: 'admin', description: 'Administrateur' },
    { name: 'customer', description: 'Client' },
    { name: 'seller', description: 'Vendeur' },
  ];
  for (const roleData of roles) {
    const exists = await roleRepository.findOne({ where: { name: roleData.name } });
    if (!exists) {
      await roleRepository.save(roleData);
    }
  }
}
